var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"오르카의 행방을 찾았습니다.","JPN":"オルカが見つかりました。","ENG":"I have located Orca.","TWN":"我發現奧爾卡的行蹤了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"왠 용병 둘과 도시외곽에서 지내고 있었어요.","JPN":"二人の傭兵と郊外で暮らしています。","ENG":"She's living with two other mercenaries in the city outskirts.","TWN":"他現在跟兩個傭兵在郊外生活。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"잠깐. 내가 지금 제대로 들은 건가?","JPN":"待て。今、何と言った？","ENG":"Wait. Did I hear that right?","TWN":"等等，我沒有聽錯吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"오르카가 사람들과 함께 지내고 있다고?","JPN":"オルカが他人と一緒に暮らしてるだと？","ENG":"Orca is living together with other people?","TWN":"你說奧爾卡跟其他人在一起？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 이번엔 제대로 들으신 것 같아 다행이네요.","JPN":"はい、その通りです。","ENG":"Yes. I'm glad you heard that right this time.","TWN":"是的，很高興這次您聽得很清楚。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"침식체만 보면 눈이 뒤집히는 건 예사의 그 오르카입니다만.","JPN":"侵食体を見れば所かまわず暴れる、あのオルカですが。","ENG":"She's definitely Orca, the one that goes completely berserk at the sight of C.O.","TWN":"雖然仍是個一看到侵蝕體，就會發狂的正常奧爾卡。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"평상시엔 의외로 멀쩡히 대화도 나눌 정도로 이성을 건재하게 유지하고 있더군요.","JPN":"意外と普段はまともに会話を交わせるほど、理性を保っていました。","ENG":"Although for some reason, she is able to maintain sanity and have conversations when she's out of combat.","TWN":"但平時卻意外地保有能和人對話的理性。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"처음엔 상속된 지 얼마 되지 않아서 그런 줄 알았는데......","JPN":"初めは相続して間もないから、だと思ったのですが……","ENG":"At first, I assumed that it was because she inherited the Watch just recently...","TWN":"我一開始以為她才剛繼承奧爾卡沒多久……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"수집한 정보에 의하면 그런 모습으로 활약한지 꽤 오래된 모양입니다.","JPN":"集めた情報によれば、かなり長い間その姿で活躍してきたようです。","ENG":"But based on the collected information, she has been like that for quite some time.","TWN":"但根據收集的情報，這種狀態好像已經持續很久了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"워치에 기억을 빼앗기지 않은 오르카라...... 전례에 없던 케이스로군.","JPN":"ウォッチに記憶を奪われないオルカか……前例のないケースだな。","ENG":"An Orca who didn't lose her memory to the Watch? That's an unprecedented case.","TWN":"沒有被能量環奪去記憶的奧爾卡……這真是史無前例的個案呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"글쎄요. 만일 기억이 온전했다면 그런 쬐끄만 여자아이가 트레일러촌에서 용병들과 함께 생활하고 있진 않았겠죠.","JPN":"どうでしょう。もし記憶があるなら、幼い女の子がトレーラーハウスで傭兵と一緒に暮らしたりしないと思います。","ENG":"Well, if she really kept her memory, a little girl like her shouldn't be living with mercenaries in a trailer park.","TWN":"這不一定。如果記憶完整的話，那麼小的女孩子是不會在卡車營地裡，和傭兵一起生活吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"음? 오르카가 여자아이라고?","JPN":"ん？オルカは女の子なのか？","ENG":"Huh? Orca is a little girl?","TWN":"嗯？你說奧爾卡是女孩？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이것 참...... 놀라움의 연속인걸.","JPN":"まったく……、驚かされてばかりだな。","ENG":"Oh wow... It's just one surprise after another.","TWN":"這可真是……驚奇不斷呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"놈은 침식체를 죽일 수만 있다면, 어떤 몸이 숙주가 되든 상관없다는 거겠죠.","JPN":"やつは侵食体を殺せれば、どんな体が宿主でも構わないのでしょう。","ENG":"Seems like Orca doesn't care who the host is, as long as it's able to kill C.O.","TWN":"只要能殺死侵蝕體，那傢伙不會在乎宿主是什麼樣的身體吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"못쓸 정도로 망가졌을 땐, 다시 새로운 몸을 찾으면 그만이니까요.","JPN":"使えないほど壊れてしまったら、新しい体を探せばいいだけですから。","ENG":"If the host's body is seriously damaged, it just has to find a new one."},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......뭐, 방식은 마음에 안 들지만 섣불리 파괴할 수는 없는 노릇이지.","JPN":"……まあ、やり方は気に入らないが、だからといってうかつに手を出すわけにもいかない。","ENG":"Well, I don't like its methods, but we can't just outright destroy it.","TWN":"……這個嘛，雖然不喜歡這種方式，但奧爾卡也不會輕易破壞宿主的身體吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"지금은 비록 정신이 온전해 보여도, 실상은 벼랑 끝에 내몰려있을 가능성이 높아.","JPN":"今は理性を保っているように見えても、相当追い込まれている可能性が高い。","ENG":"It may look like she's maintaining her sanity, but it's highly likely that she is at the edge of a cliff.","TWN":"目前雖然看起來很正常，但實際上有很大的可能，她已經被逼到懸崖邊緣了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"우리가 데려와서 직접 보호관찰을 하는 건 어떻겠나?","JPN":"連れて来て保護観察とするのはどうだ？","ENG":"Why don't we bring her in to place her under probation?","TWN":"妳覺得我們把她帶過來，直接進行保護觀察怎麼樣？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"후, 수지타산적인 면에서 절대적으로 손해이긴 합니다만......","JPN":"はあ……、損をするだけで、まったく割に合いませんが……","ENG":"*Sigh* It would be a huge loss for our company...","TWN":"呼，這在收支方面絕對是虧損……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하필 놈의 타깃이 아이라서 저도 그냥 두고 볼 수만은 없겠네요.","JPN":"だからといって、ターゲットが子供なので、見過ごすわけにもいきません。","ENG":"But since its host is a child, I don't think I can just ignore it.","TWN":"但偏偏那傢伙的目標是小孩子，我也不能就這樣坐視不管。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};